A debounce function limits how often a function can be called by delaying its execution until after a specified wait time has passed since the last invocation.

```javascript
// Debounce function that delays calling fn until after wait milliseconds have elapsed
function debounce(fn, wait) {
  let timeout;
  return function (...args) {
    clearTimeout(timeout);
    timeout = setTimeout(() => fn.apply(this, args), wait);
  };
}

// Example: Log search query only after user stops typing for 300ms
const search = (query) => console.log("Searching for:", query);
const debouncedSearch = debounce(search, 300);

// Simulate input events
debouncedSearch("a");        // No immediate log
setTimeout(() => debouncedSearch("ab"), 200);
setTimeout(() => debouncedSearch("abc"), 400); // Only this will log "Searching for: abc"
```
